INSERT INTO public.journals (id, user_id, content, character_id, created_at, title, updated_at) VALUES ('96ad559c-9bce-4bfe-88dc-afb7d1945018', '31fa4150-9464-43c5-90c8-5ea5cfc664d7', '<p><strong>Magia blanca</strong></p><p><br></p><ol><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span>Read Languages.</li></ol><p><br></p><p><strong>Magia negra</strong></p><p><br></p><ol><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span>Ventriloquismo.</li></ol><p><br></p><p><strong>Magia gris</strong></p><p><br></p><ol><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span>Hold Portal.</li></ol><p><br></p><p><strong>Magia natural</strong></p><p><br></p><ol><li data-list="bullet"><span class="ql-ui" contenteditable="false"></span>Detect animals or plants.</li></ol>', 'e4b3fad5-8659-4d40-be9b-84fc41deee44', '2025-06-01 23:02:06.30404', 'Grimorio', '2025-06-01 23:02:06.30404');
INSERT INTO public.journals (id, user_id, content, character_id, created_at, title, updated_at) VALUES ('8b91a11f-5358-43ff-b670-d4262f250486', 'bafbefd7-7b5a-4e94-90e6-ec02bc93f51c', '<p>Vael''tharion debe un favor a un nigromante malvado</p>', NULL, '2025-06-06 00:46:11.385032', 'Vael''tharion Deuda', '2025-06-06 00:46:11.385032');
INSERT INTO public.journals (id, user_id, content, character_id, created_at, title, updated_at) VALUES ('cd503f36-3645-4dbb-8c0c-42fcd4dbcbd1', '836b6c81-8cd3-4ceb-9b2b-d2f98da29ff2', '<p>En el bosque habia un templo en el bosque aliado o enemigo de los dragones que practicaban magia elemental. Lo q puede crear anomalias climaticas.</p>', '7202b169-1016-421f-a017-300f897c96b5', '2025-07-26 21:39:54.404484', 'Templo de la Maldad Elemental (Mito Draconico)', '2025-07-26 21:39:54.404484');
INSERT INTO public.journals (id, user_id, content, character_id, created_at, title, updated_at) VALUES ('175d3f26-5f80-4357-8a07-19195f5ecc92', '836b6c81-8cd3-4ceb-9b2b-d2f98da29ff2', '<p>Informacion que nos dio Terjon (Puede ser verdad o no): </p><p>A Yavo: " A dos dias de donde se encontraron con los Goblin pude encontrar la entrada a su guarida. Parecen estar colaborando con Humanos y Bandidos. Llevando objetos de valor robados de caravanas ".</p><p><br></p><p>A Vael''Tharion: " Los pastos congelados deben tener que ver con el desbalance que esta investigando Meara. Hay fenomenos naturales pasando por todos los alrededores ", " Las huellas de 3 dedos, deben ser de hombres reptil cerca del pantano al Noroeste a unos 3 dias, si van a ir a investigar el origen de los hombres reptil, por nada en el mundo crucen los rios sin haberlos investigado bien, tienen serpientes marinas cuidando las entradas a las guaridas ".</p><p><br></p><p>A Veal''Saria: " Nuestros roles fueron otorgados por el mismo Meara, somos 2 aqui en este bosque. Yo me encargo del balance natural aqui cerca de Hommlet. Ella se encarga de Ilmire, no le crean es una serpiente. Se llama Elowen. Ella no sigue el camino natural unicamente sino que tambien comulga con los Fey, nadie que comulgue con los Feys puede ser de fiar ". " Tengan cuidado si van a tomar un barco que salga de Hommlet dura la luna llena, durante la luna llena el mar trae los susurruos de la locura a los marinos "</p><p><br></p><p>A Baudo: " Cuidado sin viajan mucho mas directamente al Este, intenten tomar un desvio a Ilmire. Todavia nadie ha podido lidiar con los problemas entre los Fey y el Wyrm Negro (Lagarto grande, son inteligentes). Esta en algun lado escondido en algunas ruinas elficas junto con todos sus tesoros. Curiosamente se dice que guarda una espada capaz de dañar a Draconidos ".</p><p> </p><p>A Iri: " Si llegan a encontrar una de las entradas al templo, al ir a recoger las hierbas, si deciden adentrarse, no tomen las aguas dentro del templo. Es cierto que otorgan la inmortalidad pero te esclavizan ". " Las cavernas que resguardan las serpientes marinas de las guaridas de los hombres reptil tienen Dopplegangers. Tienen una reina que puede llegar a ser un Corazon de una Mazmorra ".</p><p><br></p><p>A Desmonc: " Tiene la teoria de que la niebla debe estar conectada a los avistamientos de elementales en las costas de Hommlet ". " El mayor problema que tenemos ahora es la disputa entre el Wyrm y los Fey, pero el problema de los avistamientos de Goblins y secuestros de gente inocente ". " Problemas sin explicacion parecen apilarse cada vez mas y mas, siento que es una carga mas pesada de la que puedo manejar ".</p><p><br></p><p>" El fuerte es una causa perdida, hay 2 locos luchando contra la corrupcion de Ilmiyer. Parece haber una infeccion mental o psiquica. Si van a ir a Ilmiyer, les diria que no confien mucho con el jefe de la guardia de Ilmiyer, ni Elowen, si pueden no confien en nadie de Ilmiyer ".</p><p><br></p><p>Para encontrar las hierbas hay q buscar un roble que conecta con un subterraneo.</p>', '7202b169-1016-421f-a017-300f897c96b5', '2025-07-26 22:19:11.48908', 'Terjon (Druida Deprimido del Bosque de Meara)', '2025-07-26 22:19:11.48908');
